package com.companionlink.servlet.admin;
import com.companionlink.dao.ActivityTypeDAO; import com.companionlink.model.ActivityType; import com.companionlink.servlet.BaseServlet; import com.companionlink.util.ValidationUtils;
import jakarta.servlet.*; import jakarta.servlet.annotation.WebServlet; import jakarta.servlet.http.*; import java.io.IOException;
@WebServlet("/admin/activities") public class AdminActivitiesServlet extends BaseServlet { private final ActivityTypeDAO dao=new ActivityTypeDAO(); protected void doGet(HttpServletRequest r,HttpServletResponse h)throws ServletException,IOException{r.setAttribute("activities",dao.findAll(false));forward(r,h,"admin/activities");} protected void doPost(HttpServletRequest r,HttpServletResponse h)throws ServletException,IOException{try{String action=r.getParameter("action"); if("delete".equals(action)){dao.deactivate(Integer.parseInt(r.getParameter("id")));ok(r,h,"/admin/activities","Activity deactivated.");return;} if(ValidationUtils.isBlank(r.getParameter("name")))throw new IllegalArgumentException("Name is required."); ActivityType a=new ActivityType();a.setName(r.getParameter("name"));a.setDescription(r.getParameter("description")); if("update".equals(action)){a.setId(Integer.parseInt(r.getParameter("id")));a.setActive("true".equals(r.getParameter("active")));dao.update(a);ok(r,h,"/admin/activities","Activity updated.");}else{dao.create(a);ok(r,h,"/admin/activities","Activity created.");}}catch(Exception e){r.setAttribute("error",e.getMessage());r.setAttribute("activities",dao.findAll(false));forward(r,h,"admin/activities");}}}
